import { Component, Host, Prop, State, Watch, h } from '@stencil/core';
import { Booking } from '@/models/booking.dto';
import { IEntries } from '@/models/IBooking';
import { CityLedgerService } from '@/services/city-ledger';
import type { ServiceCategoryOption } from '@/components/ir-city-ledger/ir-city-ledger-folio/ir-city-ledger-transaction-drawer/ir-city-ledger-transaction-form/ir-city-ledger-transaction-form.schema';
import { mapClTxToFolioRow, FolioRow } from '@/components/ir-city-ledger/ir-city-ledger-folio/types';
import moment from 'moment';

@Component({
  tag: 'ir-booking-city-ledger',
  styleUrls: ['ir-booking-city-ledger.css', '../../../common/table.css'],
  scoped: true,
})
export class IrBookingCityLedger {
  private cityLedgerService = new CityLedgerService();

  /** Booking object; component is hidden when booking.agent is null. */
  @Prop() booking: Booking;

  /** Active language code. */
  @Prop() language: string = 'en';

  /** Currency symbol used in the transaction drawer. */
  @Prop() currencySymbol: string = '$';

  /** Service-category entries used to populate the transaction form. */
  @Prop() svcCategories: IEntries[] = [];

  @State() private isLoading: boolean = false;
  @State() private folioRows: FolioRow[] = [];
  @State() private drawerOpen: boolean = false;
  @State() private error: string | null = null;

  componentWillLoad() {
    if (this.booking?.agent) {
      this.fetchCityLedger();
    }
  }

  @Watch('booking')
  handleBookingChange(newVal: Booking, oldVal: Booking) {
    const agentChanged = newVal?.agent?.id !== oldVal?.agent?.id;
    const datesChanged = newVal?.from_date !== oldVal?.from_date || newVal?.to_date !== oldVal?.to_date;
    if (newVal?.agent && (agentChanged || datesChanged)) {
      this.fetchCityLedger();
    }
  }

  private async fetchCityLedger() {
    if (!this.booking?.agent) return;
    this.isLoading = true;
    this.error = null;
    try {
      const result = await this.cityLedgerService.fetchCL({
        AGENCY_ID: this.booking.agent.id,
        START_DATE: this.booking.from_date,
        END_DATE: this.booking.to_date,
        START_ROW: 0,
        END_ROW: 200,
        SEARCH_QUERY: this.booking.booking_nbr,
      });
      let runningBalance = 0;
      this.folioRows = result.My_Cl_tx.map((tx, i) => {
        runningBalance = runningBalance + tx.DEBIT - tx.CREDIT;
        return { _rowId: String(i), ...mapClTxToFolioRow(tx), balance: runningBalance };
      });
    } catch (err) {
      console.error('[ir-booking-city-ledger] fetchCL failed:', err);
      this.error = 'Failed to load city ledger.';
    } finally {
      this.isLoading = false;
    }
  }

  private get serviceCategoryOptions(): ServiceCategoryOption[] {
    return this.svcCategories.map(s => ({ id: s.CODE_NAME, label: s.CODE_VALUE_EN }));
  }

  private get bookingOptions() {
    return this.booking?.booking_nbr ? [{ id: this.booking.booking_nbr, label: `#${this.booking.booking_nbr}` }] : [];
  }

  private formatAmount(value: number): string {
    if (!value) return '—';
    return `${this.currencySymbol}${value.toFixed(2)}`;
  }

  private renderTable() {
    if (this.folioRows.length === 0) {
      return <p class="booking-city-ledger__empty">No city ledger entries for this period.</p>;
    }
    return (
      <div class="table--container booking-city-ledger__table-wrap">
        <table class="table data-table">
          <thead>
            <tr>
              <th>Status</th>
              <th>Date</th>
              <th>Description</th>
              <th class="text-right">Debit</th>
              <th class="text-right">Credit</th>
              {/* <th class="text-right">Balance</th> */}
            </tr>
          </thead>
          <tbody>
            {this.folioRows.map(row => (
              <tr key={row._rowId} class="ir-table-row">
                <td>
                  <wa-tag size="small" variant={row.status.variant as any}>
                    {row.status.label}
                    {row.status.id === 'billed' && <wa-icon name="lock"></wa-icon>}
                  </wa-tag>
                </td>
                <td class="booking-city-ledger__cell-date">{moment(row.serviceDate).format('MMM DD, YYYY')}</td>
                <td>{row.description || '—'}</td>
                <td class="text-right">{row.debit ? this.formatAmount(row.debit) : '—'}</td>
                <td class="text-right">{row.credit ? this.formatAmount(row.credit) : '—'}</td>
                {/* <td class="text-right">{this.formatAmount(row.balance)}</td> */}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }

  render() {
    if (!this.booking?.agent) {
      return <Host></Host>;
    }
    return (
      <Host>
        <wa-card class="booking-city-ledger__card">
          <div slot="header" class="booking-city-ledger__header-title">
            <p class="font-size-large p-0 m-0"> City Ledger</p>
          </div>

          <wa-tooltip for="booking-city-ledger-add-btn">Add folio entry</wa-tooltip>
          <ir-custom-button
            slot="header-actions"
            id="booking-city-ledger-add-btn"
            size="small"
            variant="neutral"
            appearance="plain"
            onClickHandler={() => (this.drawerOpen = true)}
          >
            <wa-icon name="plus" style={{ fontSize: '1rem' }}></wa-icon>
          </ir-custom-button>

          {this.isLoading ? (
            <div class="booking-city-ledger__spinner-wrap">
              <ir-spinner></ir-spinner>
            </div>
          ) : this.error ? (
            <p class="booking-city-ledger__error">{this.error}</p>
          ) : (
            this.renderTable()
          )}
        </wa-card>

        <ir-city-ledger-transaction-drawer
          open={this.drawerOpen}
          drawerLabel="New Folio Entry"
          agentId={this.booking.agent.id}
          currencySymbol={this.currencySymbol}
          serviceCategoryOptions={this.serviceCategoryOptions}
          bookingOptions={this.bookingOptions}
          onCloseDrawer={() => (this.drawerOpen = false)}
          onTransactionSaved={async () => {
            this.drawerOpen = false;
            await this.fetchCityLedger();
          }}
        ></ir-city-ledger-transaction-drawer>
      </Host>
    );
  }
}
